// BusTrendChart.js
import React from "react";

const BusTrendChart = ({ buses }) => {
  // Count bus types
  const normal = buses.filter(b => b.status === "normal").length;
  const ghost = buses.filter(b => b.status === "ghost").length;
  const anomaly = buses.filter(b => b.status === "anomaly").length;

  return (
    <div
      style={{
        position: "absolute",
        right: "10px",
        top: "10px",
        zIndex: 1000,
        width: "250px",
        background: "#fff",
        border: "1px solid #ccc",
        borderRadius: "6px",
        padding: "10px",
        boxShadow: "0 2px 6px rgba(0,0,0,0.2)"
      }}
    >
      <h4 style={{ margin: "0 0 10px 0" }}>Bus Status Trend</h4>
      <p>Normal: {normal}</p>
      <p>Ghost: {ghost}</p>
      <p>Anomaly: {anomaly}</p>
    </div>
  );
};

export default BusTrendChart;
